await ctx.saveVote('VALID');
const embed = ctx.interaction.message.embeds[0];
let fields = [...(embed.fields || [])].filter(f => !f.name.includes('COMMUNAUTÉ') && !f.name.includes('CONSENSUS'));
let voters = [];
const oldField = embed.fields?.find(f => f.name.includes('COMMUNAUTÉ'));
if (oldField) voters = oldField.value.split('\n');
const userTag = '**' + ctx.interaction.user.username + '**';
voters = voters.filter(v => !v.includes(userTag));
voters.push('🟢' + ' ' + userTag);
const vAcc = voters.filter(v => v.includes('🟢')).length;
const total = voters.length;
const p = Math.round((vAcc / (total||1)) * 100);
const bar = '█'.repeat(Math.round(p/10)) + '░'.repeat(10 - Math.round(p/10));
fields.push(
    { name: '👥 COMMUNAUTÉ', value: voters.join('\n'), inline: true },
    { name: '📊 CONSENSUS', value: '`' + bar + '` **' + p + '%**\n(' + total + ' agents)', inline: true }
);
await ctx.editReply({ embeds: [{ ...embed.toJSON(), fields }] });
await ctx.followUp('✅ **VOTE ENREGISTRÉ**', true);

